from matplotlib import pyplot as pltfrom matplotlib.patches import Rectanglefrom matplotlib.transforms import blended_transform_factory'''Settings'''ZORDER = {    "molecule": 9,    "detector": 2,    "sky": 3,    "spectrum": 4,    "planet_model": 5,    "labels": 10,}BOX_HEIGHT = 3.0TEXT_SIZE = 12ALPHA = 0.65COLORS = {    1: "#fdae2b",    2: "#fdae4b",    3: "#fdae6b",}BAR_HEIGHT = 0.02MOLECULE_COLORS = {    "CO": "#4C78A8",    "H2O": "#54A24B",    "CH4": "#F58518",    "NH3": "#E45756",    "CO2": "#B279A2",    "SiO": "#9D755D",}'''Functions molecules'''def _draw_molecule_label(ax, molecule, rectangle):        transform = blended_transform_factory(        ax.transData,        ax.transAxes,    )        ax.text(        rectangle.xy[0] + rectangle._width / 2,        0.96,        str(molecule.name),        ha="center",        va="center",        transform=transform,        zorder=ZORDER["labels"],        color=MOLECULE_COLORS.get(molecule.name),        fontweight="bold",        fontsize=TEXT_SIZE,    )def plot_molecule(molecule, ax=None, threshold=0.20):    if ax is None: _, ax = plt.subplots(figsize=(12, 6))    transform = blended_transform_factory(        ax.transData,        ax.transAxes,    )        regions = molecule.active_regions(threshold=threshold)        xmin, xmax = ax.get_xlim()        for start, end in regions:            if end < xmin or start > xmax:            continue            start = max(start, xmin)        end   = min(end, xmax)            rectangle = Rectangle(            (start, 0.92),            end - start,            BAR_HEIGHT,            transform=transform,            facecolor=MOLECULE_COLORS.get(molecule.name, "gray"),            zorder=ZORDER["molecule"],            clip_on=False,        )                _draw_molecule_label(ax, molecule, rectangle)            ax.add_patch(rectangle)                return ax'''Functions detectors'''def _draw_detector(ax, detector):                transform = blended_transform_factory(        ax.transData,        ax.transAxes,    )        rectangle = Rectangle(        (detector.wavelength_min, 0),        detector.width,        BOX_HEIGHT,        facecolor=COLORS[detector.number],        zorder=ZORDER["detector"],        transform=transform,        alpha=ALPHA,    )    ax.add_patch(rectangle)            def _draw_order_label(ax, order):    detector = order.detector2        transform = blended_transform_factory(        ax.transData,        ax.transAxes,    )        ax.text(        detector.wavelength_min + detector.width / 2,        0.97,        str(order.number),        ha="center",        va="center",        transform=transform,        zorder=ZORDER["labels"],        fontsize=TEXT_SIZE,    )            def _format_axes(ax, setting):    xmin, xmax = setting.wavelength_range    padding = 0.02 * (xmax - xmin)    ax.set_xlim(        xmin - padding,        xmax + padding,    )    ax.set_ylim(        0,        2,    )    ax.set_xlabel("Wavelength (μm)")    #ax.set_ylabel("Echelle order")    ax.set_yticks([])    ax.set_title(setting.name)        def plot_setting(setting, ax=None):    if ax is None: _, ax = plt.subplots(figsize=(12, 6))    for order in setting:        _draw_order_label(ax, order)        for detector in order:            _draw_detector(ax,detector)    _format_axes(ax, setting)    return ax